import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev:
            return None
        curr = goal
        while prev.get(curr) != start and prev.get(curr) is not None:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.5)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.0:
            continue
        score = util / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        if best_n is not None:
            return best_n
        return neighbors[0] if neighbors else None

    if isinstance(next_coord, tuple):
        return [float(next_coord[0]), float(next_coord[1])]
    return next_coord

def run_evaluation(data_path, checkpoint, output_path):
    model = load_model(checkpoint)
    data_path = Path(data_path)
    maps = []
    eval_config_path = data_path / "eval_config.json"
    if eval_config_path.exists() and eval_config_path.stat().st_size > 0:
        with open(eval_config_path) as f:
            config = json.load(f)
        if "maps" in config and isinstance(config.get("maps"), list):
            for m in config["maps"]:
                map_p = Path(m)
                if not map_p.is_absolute():
                    map_p = data_path / map_p
                maps.append(map_p)
        else:
            maps = sorted((data_path / "maps_eval").rglob("*.png"))
    else:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        train_data = Path("/data") / "maps_train"
        for typ in ["room", "tunnel", "outdoor"]:
            typ_dir = train_data / typ
            if typ_dir.exists():
                map_files = sorted(typ_dir.glob("*.png"))[:3]
                maps.extend(map_files)
    if not maps:
        maps = sorted((data_path / "maps_eval").rglob("*.png")) or sorted((Path("/data") / "maps_train").rglob("*.png"))[:9]
    maps = sorted(maps, key=str)
    print(f"Evaluating on {len(maps)} maps.")
    results = []
    per_type = defaultdict(lambda: {"explored_rate": [], "travel_distance": [], "success": []})
    total_explored = 0.0
    total_success = 0
    total_dist = 0.0
    success_count = 0
    for map_path in maps:
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            step = 0
            while step < 128:
                target = select_waypoint(obs, model)
                if target is None:
                    break
                obs, info = env.step(target)
                step += 1
                if obs.get("explored_rate", 0.0) >= 0.9999:
                    break
            metrics = env.get_metrics()
            success = 1 if metrics.get("success", False) or metrics.get("explored_rate", 0.0) > 0.9999 else 0
            explored = metrics.get("explored_rate", 0.0)
            dist = metrics.get("travel_distance", 0.0)
            env_type = get_env_type(map_path)
            results.append({
                "map_path": str(map_path),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(dist),
                "explored_rate": float(explored)
            })
            per_type[env_type]["explored_rate"].append(explored)
            per_type[env_type]["success"].append(success)
            if success:
                per_type[env_type]["travel_distance"].append(dist)
                total_dist += dist
                success_count += 1
            total_success += success
            total_explored += explored
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            env_type = get_env_type(map_path)
            results.append({
                "map_path": str(map_path),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })
            per_type[env_type]["explored_rate"].append(0.0)
            per_type[env_type]["success"].append(0)
    n = len(results)
    explored_rate = total_explored / n if n > 0 else 0.0
    success_rate = total_success / n if n > 0 else 0.0
    travel_distance = total_dist / success_count if success_count > 0 else 0.0
    per_type_summary = {}
    for t, stats in per_type.items():
        n_t = len(stats["success"])
        if n_t > 0:
            sr = sum(stats["success"]) / n_t
            er = sum(stats["explored_rate"]) / n_t
            td_list = stats["travel_distance"]
            td = sum(td_list) / len(td_list) if td_list else 0.0
            per_type_summary[t] = {
                "explored_rate": round(float(er), 4),
                "travel_distance": round(float(td), 4),
                "success_rate": round(float(sr), 4)
            }
    exploration_score = 0.0
    for res in results:
        if res["success"] == 1:
            d = res["travel_distance"]
            if d > 0:
                exploration_score += (300.0 / d)
    exploration_score = exploration_score / n if n > 0 else 0.0
    output = {
        "explored_rate": round(float(explored_rate), 4),
        "travel_distance": round(float(travel_distance), 4),
        "success_rate": round(float(success_rate), 4),
        "per_episode": results,
        "per_type": per_type_summary,
        "total_episodes": n
    }
    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    print("Local test on train subset done.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
